/**
 * Shared theme definitions for T3 Code.
 *
 * Each theme carries a set of identity `colors` (used for previews/swatches)
 * and an optional `cssProperties` map that overrides the semantic CSS custom
 * properties defined in `apps/web/src/index.css`.
 *
 * The built-in `t3-light` and `t3-dark` themes leave `cssProperties` empty
 * because the existing stylesheet already handles them via the `.dark` class
 * toggle.  Only themes that diverge from those defaults (e.g. `t3-midnight`)
 * need to supply concrete CSS values.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** The seven identity colors that represent a theme in previews & swatches. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  /** Whether this theme is visually light or dark — drives the `.dark` class. */
  readonly mode: "light" | "dark";
  readonly colors: ThemeColors;
  readonly fontFamily?: string | undefined;
  readonly fontSize?: number | undefined;
  /**
   * CSS custom-property overrides applied to `document.documentElement.style`.
   * Properties not listed here fall back to the stylesheet defaults.
   */
  readonly cssProperties: Readonly<Record<string, string>>;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

/**
 * T3 Light — the default light appearance.
 *
 * CSS custom properties are handled by the `:root` block in `index.css`, so
 * `cssProperties` is intentionally empty.
 */
const t3Light: Theme = {
  id: "t3-light",
  name: "T3 Light",
  mode: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    accent: "#4338ca",
    sidebar: "#f5f5f5",
    editor: "#ffffff",
    terminal: "#fafafa",
    statusBar: "#f5f5f5",
  },
  cssProperties: {},
} as const;

/**
 * T3 Dark — the default dark appearance.
 *
 * CSS custom properties are handled by the `@variant dark` block in
 * `index.css`, so `cssProperties` is intentionally empty.
 */
const t3Dark: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  mode: "dark",
  colors: {
    background: "#141414",
    foreground: "#f5f5f5",
    accent: "#5b5bf0",
    sidebar: "#141414",
    editor: "#141414",
    terminal: "#0a0a0a",
    statusBar: "#171717",
  },
  cssProperties: {},
} as const;

/**
 * T3 Midnight — a deeper, blue-shifted dark theme with an indigo accent.
 *
 * Because this theme diverges from the default dark palette it supplies a
 * complete set of concrete CSS values.  All values are browser-native (no
 * Tailwind-specific syntax) so they can be applied via `style.setProperty`.
 */
const t3Midnight: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  mode: "dark",
  colors: {
    background: "#0b0e14",
    foreground: "#e2e8f0",
    accent: "#6366f1",
    sidebar: "#0d1117",
    editor: "#0b0e14",
    terminal: "#060810",
    statusBar: "#111827",
  },
  cssProperties: {
    "--background": "#0b0e14",
    "--foreground": "#e2e8f0",
    "--card": "#0d1117",
    "--card-foreground": "#e2e8f0",
    "--popover": "#0d1117",
    "--popover-foreground": "#e2e8f0",
    "--primary": "#6366f1",
    "--primary-foreground": "#ffffff",
    "--secondary": "rgba(255, 255, 255, 0.04)",
    "--secondary-foreground": "#e2e8f0",
    "--muted": "rgba(255, 255, 255, 0.06)",
    "--muted-foreground": "#94a3b8",
    "--accent": "rgba(255, 255, 255, 0.06)",
    "--accent-foreground": "#e2e8f0",
    "--destructive": "#f87171",
    "--destructive-foreground": "#fca5a5",
    "--border": "rgba(255, 255, 255, 0.08)",
    "--input": "rgba(255, 255, 255, 0.10)",
    "--ring": "#6366f1",
    "--info": "#60a5fa",
    "--info-foreground": "#93c5fd",
    "--success": "#34d399",
    "--success-foreground": "#6ee7b7",
    "--warning": "#fbbf24",
    "--warning-foreground": "#fcd34d",
  },
} as const;

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

const BUILT_IN_THEMES: readonly Theme[] = [t3Dark, t3Light, t3Midnight];

const THEME_BY_ID: ReadonlyMap<string, Theme> = new Map(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

const DEFAULT_THEME_ID = "t3-dark";

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Return every built-in theme. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/** Look up a theme by its `id`. Returns `undefined` for unknown IDs. */
export function getTheme(id: string): Theme | undefined {
  return THEME_BY_ID.get(id);
}

/** The default theme ID (`"t3-dark"`). */
export function getDefaultThemeId(): string {
  return DEFAULT_THEME_ID;
}

