import { getDefaultThemeId, getTheme, listThemes } from "./themes";

describe("listThemes", () => {
  it("returns all built-in themes", () => {
    const themes = listThemes();
    expect(themes.length).toBe(3);
  });

  it("includes t3-dark, t3-light, and t3-midnight", () => {
    const ids = listThemes().map((t) => t.id);
    expect(ids).toContain("t3-dark");
    expect(ids).toContain("t3-light");
    expect(ids).toContain("t3-midnight");
  });
});

describe("getTheme", () => {
  it("returns t3-dark as a dark theme", () => {
    const theme = getTheme("t3-dark");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("dark");
    expect(theme!.name).toBe("T3 Dark");
  });

  it("returns t3-light as a light theme", () => {
    const theme = getTheme("t3-light");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("light");
    expect(theme!.name).toBe("T3 Light");
  });

  it("returns t3-midnight as a dark theme", () => {
    const theme = getTheme("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("dark");
    expect(theme!.name).toBe("T3 Midnight");
  });

  it("returns undefined for unknown theme IDs", () => {
    expect(getTheme("nonexistent")).toBeUndefined();
    expect(getTheme("")).toBeUndefined();
  });

  it("provides all seven identity colors for every theme", () => {
    const keys = [
      "background",
      "foreground",
      "accent",
      "sidebar",
      "editor",
      "terminal",
      "statusBar",
    ] as const;

    for (const theme of listThemes()) {
      for (const key of keys) {
        expect(theme.colors[key]).toBeTruthy();
      }
    }
  });

  it("provides cssProperties for t3-midnight", () => {
    const theme = getTheme("t3-midnight")!;
    expect(Object.keys(theme.cssProperties).length).toBeGreaterThan(0);
