    expect(theme.cssProperties["--foreground"]).toBeDefined();
    expect(theme.cssProperties["--primary"]).toBeDefined();
  });
});

describe("getDefaultThemeId", () => {
  it("returns t3-dark", () => {
    expect(getDefaultThemeId()).toBe("t3-dark");
  });

  it("maps to a valid theme", () => {
    expect(getTheme(getDefaultThemeId())).toBeDefined();
  });
});

