import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getDefaultThemeId,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/** The special preference value meaning "auto-select based on OS setting". */
const SYSTEM_PREFERENCE = "system";

// ---------------------------------------------------------------------------
// Module-level state (external store for useSyncExternalStore)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

/** CSS custom-property names that were applied to `<html>` by the last theme. */
let appliedPropertyNames: string[] = [];

type ThemeSnapshot = {
  /** The stored preference – either `"system"` or a theme id. */
  themeId: string;
  /** The fully resolved Theme object. */
  resolved: Theme;
  /** Whether the OS currently prefers dark – only relevant when themeId is "system". */
  systemDark: boolean;
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read the stored preference from localStorage, migrating legacy values.
 *
 * Legacy values (`"light"`, `"dark"`, `"system"`) are mapped to theme IDs so
 * users who set a preference before the theme system was introduced keep a
 * seamless experience.
 */
function getStored(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === null || raw === SYSTEM_PREFERENCE) return SYSTEM_PREFERENCE;
  // Legacy migration
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  return raw;
}

/**
 * Resolve a preference string into a concrete `Theme` object.
 *
 * - `"system"` → pick the default light/dark theme based on OS preference.
 * - Any other string → look up by ID, falling back to the default theme.
 */
function resolveTheme(preference: string): Theme {
  if (preference === SYSTEM_PREFERENCE) {
    const id = getSystemDark() ? "t3-dark" : "t3-light";
    return getTheme(id) ?? getTheme(getDefaultThemeId())!;
  }
  return getTheme(preference) ?? getTheme(getDefaultThemeId())!;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle the .dark class (drives Tailwind's dark variant)
  root.classList.toggle("dark", theme.mode === "dark");

  // Remove any CSS custom properties set by the previous theme
  for (const name of appliedPropertyNames) {
    root.style.removeProperty(name);
  }

  // Apply CSS custom properties from the new theme
  const nextNames: string[] = [];
  for (const [prop, value] of Object.entries(theme.cssProperties)) {
    root.style.setProperty(prop, value);
    nextNames.push(prop);
  }
  appliedPropertyNames = nextNames;

  // Apply optional font overrides
  if (theme.fontFamily) {
    document.body.style.fontFamily = theme.fontFamily;
  } else {
    document.body.style.removeProperty("font-family");
  }

  if (theme.fontSize !== undefined) {
    root.style.fontSize = `${String(theme.fontSize)}px`;
  } else {
    root.style.removeProperty("font-size");
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyThemeToDOM(resolveTheme(getStored()));

// ---------------------------------------------------------------------------
// Snapshot (useSyncExternalStore)
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const themeId = getStored();
  const systemDark = themeId === SYSTEM_PREFERENCE ? getSystemDark() : false;
  const resolved = resolveTheme(themeId);

  if (
    lastSnapshot &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.resolved.id === resolved.id
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId, resolved, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === SYSTEM_PREFERENCE) {
      applyThemeToDOM(resolveTheme(SYSTEM_PREFERENCE), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyThemeToDOM(resolveTheme(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = snapshot.resolved.mode;

  const setTheme = useCallback((next: string) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyThemeToDOM(resolveTheme(next), true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount / preference change
  useEffect(() => {
    applyThemeToDOM(snapshot.resolved);
  }, [snapshot.resolved]);

  return {
    /** The stored preference – `"system"` or a theme id like `"t3-dark"`. */
    theme: snapshot.themeId,
    /** Set the active preference. Pass `"system"` for OS-based auto-selection. */
    setTheme,
    /** Binary resolved mode – always `"light"` or `"dark"`. */
    resolvedTheme,
    /** The full resolved Theme object for the currently active theme. */
    currentTheme: snapshot.resolved,
    /** All available built-in themes. */
    availableThemes: listThemes(),
  } as const;
}

