import { memo, useCallback } from "react";
import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

// ---------------------------------------------------------------------------
// Swatch preview
// ---------------------------------------------------------------------------

/** Renders a row of small color circles representing a theme's identity palette. */
function ThemeSwatch({ colors }: { colors: Theme["colors"] }) {
  const swatches = [
    colors.background,
    colors.sidebar,
    colors.editor,
    colors.accent,
    colors.foreground,
  ];

  return (
    <div className="flex gap-1.5">
      {swatches.map((color, i) => (
        <span
          key={i}
          className="size-3.5 rounded-full border border-white/20 shadow-sm"
          style={{ backgroundColor: color }}
          aria-hidden="true"
        />
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Theme card
// ---------------------------------------------------------------------------

function ThemeCard({
  theme,
  selected,
  onSelect,
}: {
  theme: Theme;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={cn(
        "flex w-full flex-col gap-2.5 rounded-lg border px-3 py-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onSelect}
    >
      {/* Mini preview bar */}
      <div
        className="flex h-10 w-full items-end gap-px overflow-hidden rounded-md border border-black/10"
        aria-hidden="true"
      >
        {/* Sidebar stripe */}
        <div className="h-full w-5 shrink-0" style={{ backgroundColor: theme.colors.sidebar }} />
        {/* Editor area */}
        <div
          className="relative flex h-full flex-1 flex-col justify-end"
          style={{ backgroundColor: theme.colors.editor }}
        >
          {/* Faux text lines */}
          <div className="flex flex-col gap-[3px] p-1">
            <div
              className="h-[3px] w-3/4 rounded-full opacity-30"
              style={{ backgroundColor: theme.colors.foreground }}
            />
            <div
              className="h-[3px] w-1/2 rounded-full opacity-20"
              style={{ backgroundColor: theme.colors.foreground }}
            />
          </div>
        </div>
        {/* Status bar */}
        <div
          className="h-2.5 w-full absolute bottom-0 left-0"
          style={{ backgroundColor: theme.colors.statusBar, position: "absolute" }}
        />
      </div>

      <div className="flex items-center justify-between gap-2">
        <div className="flex flex-col gap-1">
          <span className="text-sm font-medium">{theme.name}</span>
          <ThemeSwatch colors={theme.colors} />
        </div>

        {selected ? (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector (public)
// ---------------------------------------------------------------------------

export const ThemeSelector = memo(function ThemeSelector() {
  const { theme, setTheme, resolvedTheme, currentTheme, availableThemes } = useTheme();
  const isSystem = theme === "system";

  const handleSystemToggle = useCallback(() => {
    setTheme("system");
  }, [setTheme]);

  return (
    <div className="space-y-3">
      {/* System preference option */}
      <button
        type="button"
        role="radio"
        aria-checked={isSystem}
        className={cn(
          "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
          isSystem
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent",
        )}
        onClick={handleSystemToggle}
      >
        <span className="flex flex-col">
          <span className="text-sm font-medium">System</span>
          <span className="text-xs">
            Automatically match your operating system appearance.
          </span>
        </span>
        {isSystem ? (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </button>

      {/* Theme cards */}
      <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Theme selection">
        {availableThemes.map((t) => (
          <ThemeCard
            key={t.id}
            theme={t}
            selected={!isSystem && theme === t.id}
            onSelect={() => setTheme(t.id)}
          />
        ))}
      </div>

      {/* Active theme indicator */}
      <p className="text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{currentTheme.name}</span>
        {isSystem ? (
          <span className="text-muted-foreground"> (via {resolvedTheme} system preference)</span>
        ) : null}
      </p>
    </div>
  );
});

